-- İhracat Onayları verileri
-- Oluşturulma: 2026-02-04 23:34:11

DROP TABLE IF EXISTS `oner_i_hracat_onaylari`;

CREATE TABLE `oner_i_hracat_onaylari` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `onay_numarasi` VARCHAR(500),
  `firmanin_unvani` VARCHAR(500),
  `urunun_kategorisi` TEXT,
  `ihracat_onayi_aldigi_ulke` VARCHAR(500),
  `onayin_durumu` VARCHAR(500),
  `gosterim_icin_deger` DOUBLE,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

